<h1>Cart</h1><?php $total=0; foreach($items as $p): $total+=$p['line_total'];?><div class="card"><h3><?=$p['title']?></h3><p><?=H::money($p['line_total'])?></p><form method="post" action="/cart/license/<?=$p['id']?>"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><label><input type="checkbox" name="commercial" <?=$p['commercial_selected']?'checked':''?>> Commercial license</label><button>Update</button></form><form method="post" action="/cart/remove/<?=$p['id']?>"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><button>Remove</button></form></div><?php endforeach;?><h2>Total <?=H::money($total)?></h2><a class="btn" href="/checkout">Checkout</a>
